import { readFileSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";

const cssRoot = resolve(process.cwd(), "assets", "css");
const sources = [
  ["base.css", "reset"],
  ["tokens.css", "tokens"],
  ["foundations.css", "foundations"],
  ["premium-experience.css", "pages"],
  ["motion.css", "components"],
  ["portal.css", "pages"],
  ["responsive.css", "utilities"],
  ["live-refinement.css", null],
  ["visual-refinement.css", null],
  ["visual-contrast-fix.css", null],
  ["module-media-sanity.css", null],
  ["module-art-direction.generated.css", null],
  ["nutraxin-catalogue.css", null],
  ["cro.css", null],
  ["oncology.css", null],
  ["ai-search.css", null]
];

const sections = sources.map(([filename, layer]) => {
  const css = readFileSync(resolve(cssRoot, filename), "utf8").trim();
  const labelled = `/* Source: ${filename} */\n${css}`;
  return layer ? `@layer ${layer} {\n${labelled}\n}` : labelled;
});

const bundle = `/* Generated by scripts/build-css-bundle.mjs. Edit the source stylesheets, not this file. */
@layer reset, tokens, foundations, layout, components, pages, utilities;

${sections.join("\n\n")}\n`;

writeFileSync(resolve(cssRoot, "novapharm.bundle.css"), bundle);
console.log(`Bundled ${sources.length} source stylesheets into assets/css/novapharm.bundle.css.`);
